head.b:skin:
/* ─── 기본 초기화 ─── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: 'Segoe UI', 'Apple SD Gothic Neo', 'Noto Sans KR', sans-serif;
  background: #f0f4f8;
  color: #1e2a3a;
  font-size: 16px;
  line-height: 1.7;
}
a { color: inherit; text-decoration: none; }
img { max-width: 100%; height: auto; display: block; }

/* ─── 헤더 ─── */
#header-wrap {
  background: #0d1b2a;
  color: #e0f0ff;
  padding: 0;
  position: sticky;
  top: 0;
  z-index: 100;
  box-shadow: 0 2px 12px rgba(0,200,255,.15);
  border-bottom: 2px solid #00c8ff;
}
#header-inner {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
  height: 60px;
}
#header-inner h1 a {
  font-size: 1.4rem;
  font-weight: 700;
  color: #00c8ff;
  letter-spacing: 0.5px;
  font-family: 'Courier New', monospace;
}
.header-nav {
  display: flex;
  gap: 20px;
  list-style: none;
}
.header-nav a {
  color: rgba(200,230,255,.8);
  font-size: .88rem;
  transition: color .2s;
  font-weight: 500;
}
.header-nav a:hover { color: #00c8ff; }

/* ─── 히어로 배너 (홈만) ─── */
.hero-banner {
  background: linear-gradient(135deg, #0d1b2a 0%, #0a2540 60%, #0d3460 100%);
  color: #e0f0ff;
  text-align: center;
  padding: 65px 20px;
  border-bottom: 1px solid rgba(0,200,255,.2);
}
.hero-banner h2 {
  font-size: 2rem;
  margin-bottom: 12px;
  color: #00c8ff;
  font-family: 'Courier New', monospace;
  letter-spacing: 1px;
}
.hero-banner p {
  font-size: 1rem;
  opacity: .8;
  max-width: 520px;
  margin: 0 auto;
}

/* ─── 레이아웃 래퍼 ─── */
#main-wrap {
  max-width: 1100px;
  margin: 36px auto;
  padding: 0 20px;
  display: grid;
  grid-template-columns: 1fr 290px;
  gap: 28px;
}
@media (max-width: 768px) {
  #main-wrap { grid-template-columns: 1fr; }
}

/* ─── 포스트 그리드 ─── */
#content { min-width: 0; }
.blog-posts {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 22px;
}
@media (max-width: 600px) {
  .blog-posts { grid-template-columns: 1fr; }
}

/* ─── 포스트 카드 ─── */
.post-card {
  background: #fff;
  border-radius: 10px;
  overflow: hidden;
  box-shadow: 0 2px 12px rgba(0,0,0,.06);
  border: 1px solid #e0eaf4;
  transition: transform .2s, box-shadow .2s, border-color .2s;
}
.post-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 28px rgba(0,200,255,.12);
  border-color: #00c8ff;
}
.post-card-thumb {
  width: 100%;
  height: 190px;
  object-fit: cover;
}
.post-card-thumb-placeholder {
  width: 100%;
  height: 190px;
  background: linear-gradient(135deg, #0d1b2a, #0a2540);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #00c8ff;
  font-size: 2.5rem;
  font-family: monospace;
}
.post-card-body { padding: 16px; }
.post-card-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 8px;
}
.post-card-label {
  background: #e6f7ff;
  color: #0077aa;
  font-size: .72rem;
  padding: 2px 9px;
  border-radius: 4px;
  font-weight: 700;
  font-family: monospace;
  letter-spacing: .3px;
}
.post-card-title {
  font-size: .98rem;
  font-weight: 700;
  line-height: 1.4;
  margin-bottom: 8px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.post-card-title a:hover { color: #00c8ff; }
.post-card-snippet {
  font-size: .84rem;
  color: #667;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 10px;
}
.post-card-meta { font-size: .76rem; color: #aab; }

/* ─── 사이드바 ─── */
#sidebar { min-width: 0; }
.sidebar-widget {
  background: #fff;
  border-radius: 10px;
  padding: 18px;
  margin-bottom: 22px;
  box-shadow: 0 2px 12px rgba(0,0,0,.05);
  border: 1px solid #e0eaf4;
}
.sidebar-widget-title {
  font-size: .95rem;
  font-weight: 700;
  margin-bottom: 12px;
  padding-bottom: 8px;
  border-bottom: 2px solid #00c8ff;
  color: #0d1b2a;
  font-family: monospace;
  letter-spacing: .5px;
  text-transform: uppercase;
}

/* ─── 글 상세 페이지 ─── */
.post-detail {
  background: #fff;
  border-radius: 10px;
  padding: 32px;
  box-shadow: 0 2px 12px rgba(0,0,0,.06);
  border: 1px solid #e0eaf4;
}
.post-detail h1 {
  font-size: 1.65rem;
  line-height: 1.35;
  margin-bottom: 12px;
  color: #0d1b2a;
}
.post-detail-meta {
  font-size: .84rem;
  color: #aab;
  margin-bottom: 24px;
  padding-bottom: 14px;
  border-bottom: 1px solid #eef2f7;
  font-family: monospace;
}
.post-detail-body { font-size: 1rem; line-height: 1.9; }
.post-detail-body h2 {
  font-size: 1.3rem;
  margin: 36px 0 12px;
  padding-left: 14px;
  border-left: 4px solid #00c8ff;
  color: #0d1b2a;
}
.post-detail-body h3 {
  font-size: 1.05rem;
  margin: 22px 0 8px;
  color: #334;
}
.post-detail-body p { margin-bottom: 14px; }
.post-detail-body ul, .post-detail-body ol {
  padding-left: 20px;
  margin-bottom: 14px;
}
.post-detail-body li { margin-bottom: 6px; }
.post-detail-body code {
  background: #f0f4f8;
  border: 1px solid #d0dce8;
  padding: 1px 6px;
  border-radius: 4px;
  font-family: 'Courier New', monospace;
  font-size: .9em;
  color: #0077aa;
}
.post-detail-body table {
  width: 100%;
  border-collapse: collapse;
  margin: 20px 0;
  font-size: .9rem;
}
.post-detail-body td, .post-detail-body th {
  border: 1px solid #d8e8f0;
  padding: 10px 12px;
  text-align: left;
}
.post-detail-body th {
  background: #e6f7ff;
  font-weight: 700;
  color: #0077aa;
  font-family: monospace;
}
.post-detail-body blockquote {
  background: #e6f7ff;
  border-left: 4px solid #00c8ff;
  padding: 14px 18px;
  margin: 20px 0;
  border-radius: 0 8px 8px 0;
  color: #334;
  font-style: italic;
}
.post-detail-body img {
  max-width: 100%;
  border-radius: 8px;
  margin: 16px auto;
  border: 1px solid #e0eaf4;
}

/* ─── 페이지네이션 ─── */
.blog-pager {
  display: flex;
  justify-content: space-between;
  margin-top: 32px;
  gap: 12px;
}
.blog-pager a {
  background: #0d1b2a;
  color: #00c8ff;
  padding: 10px 22px;
  border-radius: 6px;
  font-size: .88rem;
  font-weight: 700;
  border: 1px solid #00c8ff;
  font-family: monospace;
  transition: background .2s, color .2s;
}
.blog-pager a:hover { background: #00c8ff; color: #0d1b2a; }

/* ─── 푸터 ─── */
#footer-wrap {
  background: #0d1b2a;
  color: rgba(200,230,255,.5);
  text-align: center;
  padding: 28px 20px;
  font-size: .84rem;
  margin-top: 60px;
  border-top: 2px solid rgba(0,200,255,.2);
  font-family: monospace;
}
#footer-wrap a { color: #00c8ff; }

/* ─── 라벨 페이지 ─── */
.label-list { list-style: none; }
.label-list li {
  padding: 8px 0;
  border-bottom: 1px solid #eef2f7;
  display: flex;
  justify-content: space-between;
  font-size: .88rem;
}
.label-list li:last-child { border-bottom: none; }
.label-list a:hover { color: #00c8ff; }
